// Regenerates src/data/english/_meta.generated.ts — a slim, meta-only index of the
// English article library (no article bodies). Consumers that only need meta (the
// internal student-detail "recommend an article" widget) import the generated file
// instead of src/data/english/index.ts, whose eager import.meta.glob otherwise
// bundles all ~215 full article files (~11MB) into that page's SSR chunk.
//
// The article modules can't be loaded through index.ts here (it uses Vite's
// import.meta.glob, unavailable in plain node), so we read the directory and
// dynamic-import each plain-TS article file via tsx.
//
//   Run:  npm run gen-english-meta   (re-run after the daily-english skill adds articles)
import { writeFileSync, readdirSync } from 'node:fs';
import { fileURLToPath, pathToFileURL } from 'node:url';
import { dirname, join } from 'node:path';

const __dirname = dirname(fileURLToPath(import.meta.url));
const dir = join(__dirname, '../src/data/english');

const files = readdirSync(dir).filter(
  (f) => f.endsWith('.ts') && !['index.ts', 'types.ts'].includes(f) && !f.endsWith('.generated.ts'),
);

const meta = [];
for (const f of files) {
  try {
    const mod = await import(pathToFileURL(join(dir, f)).href);
    const a = mod.article;
    if (!a || !a.meta) continue;
    meta.push({
      slug: f.replace(/\.ts$/, ''),
      title: a.meta.title,
      titleZh: a.meta.titleZh ?? '',
      cefr: a.meta.cefr,
      words: a.meta.wordCount,
      minutes: a.meta.readingMinutes,
    });
  } catch (e) {
    // One broken article file shouldn't abort the whole regeneration.
    console.warn(`⚠️  Skipping ${f}: ${e.message}`);
  }
}
// Stable order (by slug, newest-first) so regenerating produces minimal diffs.
meta.sort((x, y) => y.slug.localeCompare(x.slug));

const out = join(dir, '_meta.generated.ts');
const body = `// AUTO-GENERATED by scripts/gen-english-meta.mjs — DO NOT EDIT BY HAND.
// Slim meta-only index of the English article library (no article bodies) so
// consumers like the internal student page don't bundle ~11MB of full articles.
// Regenerate after adding articles:  npm run gen-english-meta

export interface EnglishArticleMeta {
  slug: string;
  title: string;
  titleZh: string;
  cefr: string;
  words: number;
  minutes: number;
}

export const englishArticleMeta: EnglishArticleMeta[] = ${JSON.stringify(meta, null, 2)};
`;
writeFileSync(out, body, 'utf8');
console.log(`✓ Wrote ${meta.length} article meta entries to ${out}`);
